float rankine_active_pressure(float phi_deg, float gamma_kNm3, float depth_m, float cohesion_kPa) {
  float phi = phi_deg * PI / 180.0f;
  float Ka = (1.0f - sin(phi)) / (1.0f + sin(phi));
  float s = Ka * gamma_kNm3 * depth_m - 2.0f * cohesion_kPa * sqrt(Ka);
  return (s < 0.0f) ? 0.0f : s;
}
